import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"1.1.核心规则","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/1.核心规则/1.1.核心规则.md","filePath":"1.基础规则/1.核心规则/1.1.核心规则.md"}'),o={name:"1.基础规则/1.核心规则/1.1.核心规则.md"};function _(b,e,d,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"_1-1-核心规则",tabindex:"-1"},[n("1.1.核心规则 "),r("a",{class:"header-anchor",href:"#_1-1-核心规则","aria-label":'Permalink to "1.1.核心规则"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序007")])])],-1),s('<h1 id="核心规则" tabindex="-1">核心规则 <a class="header-anchor" href="#核心规则" aria-label="Permalink to &quot;核心规则&quot;">​</a></h1><p>在通常情况下，本规则书的基础掷骰规则为wwx。在通常意义上，这里的wwx是指X个十面骰一次性扔出，统计其中出目为8、9、10的十面骰个数，并再投掷出目为10的骰子，以此类推直至没有10出现为止。这次掷骰行为所取得的所有成功被记录下来的骰子个数便是这次掷骰的出目<br> 当然，在某些情况下，也会出现机运骰这种掷骰方式，在进行某些需要运气判定的时刻，掷一枚十面骰，它的出目越高便表示结果越好<br> 除此以外，还有些资源中可能会涉及到其他种类的骰子掷法，具体以该资源为准</p><p>其中，X也被称为**<em>DP</em>**，英文为Dice point，XDP就是X个同时掷出的骰子。</p><p>游戏的组建<br> 一次游戏需要有一名负责构筑世界观并给予反馈的主持人（Story teller，即st）以及数名参与这一世界观，并进行主观行为的玩家组成。</p><p>游戏内各方的职责<br> 对于St而言，其具有掌控世界如何运行的最大话语权，其职责是在进行游戏时，负责搭建一个合理的、适合游玩的影片世界。一个影片世界应该具有以下几个要素：任务、剧情、场景、NPC等。<br> ST需要引导在影片中玩家的行为、路径，鼓励其完成任务，对玩家的行为给予合适的反馈，共同的书写一段有趣的故事。<br> 对于玩家而言，玩家是一个影片的直接参与者，应该尽力参与影片的任务过程，与主持人、其他玩家一同进行一段旅程。</p><p>检定<br> 检定是一个根据人物本身某方面属性、技能、专业等因素决定其大小，并通过投掷的方式去模拟随机性的过程。通常而言，人物在尝试进行一个明确的行为时且这一行为结果不是必定成功的，都需要进行一次检定。<br> 检定通常由DP和附加成功组成，其数值代表着人物在这项检定中可能表现的期望如何。<br> 决定检定成功与否的指标则是难度（DC）。<br> 难度意味着人物进行这一次检定的挑战程度大小，难度越高，则一个检定成功的可能性会相应下降。</p><p>检定的类型<br> 检定通常分为：攻击检定、豁免检定、辅助检定<br> 攻击检定是人物的主要检定，其构成为【属性+技能+专业+辅助专业+武器伤害/法术强度+其他加值】，攻击检定常常用于和敌人进行作战，也因此其在人物的冒险中具有重要地位。<br> 豁免检定；豁免检定代表人物被迫进行的一项对抗性检定，豁免检定分为反射、强韧、意志三种类型。<br> 辅助检定：辅助检定是一个人物在旅途中可能用到的次级检定，其没有辅助专业构成。</p><p>自然骰<br> 这是一种特殊的检定，其检定数值通常为D10，自然骰一般不会被重骰，检定加减值所影响。除非一个能力特地声明了它对一类自然骰检定生效，否则均无法影响自然骰的结果。</p><p>机运骰<br> 机运骰是一个仅投掷D10的特殊检定，检定的成功数再加上人物的机运骰加值。<br> 机运骰代表你对某些事情或者行为计算因你运气而产生的额外影响。这可能是你因误打误撞而导致剧情发展方向产生了偏离。当机运骰出现1的场合，视为这一机运骰出现了大失败，始终以最差的结果计算后续事件的发生。</p><p>规则中的乘除运算<br> 涉及乘法的运算，通常先计算一个资源的加减值总和，得出一个基数X。在计算多个能力带来的乘数时，将这些能力的乘数分别独立乘以基数，然后将独立得出的结果合计计算。也因此不会出现多个将基数翻倍的资源以乘法非线性叠加运算。如：一次攻击中受到4个伤害值翻倍特性的能力作用，其结算应该是X+4*（1*2-1）*X=5X，即将这次攻击的伤害值乘5。<br> 涉及除法的运算，通常先计算一个资源的加减值总和，得出一个基数X。接着把除数先互相进行一次乘法运算，得出一个总的除数，再将基数X除以除数。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=a(o,[["render",_]]);export{f as __pageData,m as default};
